import{_ as o,o as l,c as t,ai as i}from"./chunks/framework.CsYGeNYI.js";const h=JSON.parse('{"title":"Release Checklist (npm + macOS)","description":"","frontmatter":{"summary":"Step-by-step release checklist for npm + macOS app","read_when":["Cutting a new npm release","Cutting a new macOS app release","Verifying metadata before publishing"]},"headers":[],"relativePath":"reference/RELEASING.md","filePath":"reference/RELEASING.md","lastUpdated":null}'),s={name:"reference/RELEASING.md"};function n(a,e,r,c,d,p){return l(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="release-checklist-npm-macos" tabindex="-1"><a class="header-anchor" href="#release-checklist-npm-macos">#</a> Release Checklist (npm + macOS)</h1><p>Use <code>pnpm</code> (Node 22+) from the repo root. Keep the working tree clean before tagging/publishing.</p><h2 id="operator-trigger" tabindex="-1"><a class="header-anchor" href="#operator-trigger">#</a> Operator trigger</h2><p>When the operator says “release”, immediately do this preflight (no extra questions unless blocked):</p><ul><li>Read this doc and <code>docs/platforms/mac/release.md</code>.</li><li>Load env from <code>~/.profile</code> and confirm <code>SPARKLE_PRIVATE_KEY_FILE</code> + App Store Connect vars are set (SPARKLE_PRIVATE_KEY_FILE should live in <code>~/.profile</code>).</li><li>Use Sparkle keys from <code>~/Library/CloudStorage/Dropbox/Backup/Sparkle</code> if needed.</li></ul><ol><li><strong>Version &amp; metadata</strong></li></ol><ul><li>[ ] Bump <code>package.json</code> version (e.g., <code>2026.1.29</code>).</li><li>[ ] Run <code>pnpm plugins:sync</code> to align extension package versions + changelogs.</li><li>[ ] Update CLI/version strings: <a href="https://github.com/NJX-njx/opensoul/blob/main/src/cli/program.ts" target="_blank" rel="noreferrer"><code>src/cli/program.ts</code></a> and the Baileys user agent in <a href="https://github.com/NJX-njx/opensoul/blob/main/src/provider-web.ts" target="_blank" rel="noreferrer"><code>src/provider-web.ts</code></a>.</li><li>[ ] Confirm package metadata (name, description, repository, keywords, license) and <code>bin</code> map points to <a href="https://github.com/NJX-njx/opensoul/blob/main/opensoul.mjs" target="_blank" rel="noreferrer"><code>opensoul.mjs</code></a> for <code>opensoul</code>.</li><li>[ ] If dependencies changed, run <code>pnpm install</code> so <code>pnpm-lock.yaml</code> is current.</li></ul><ol start="2"><li><strong>Build &amp; artifacts</strong></li></ol><ul><li>[ ] If A2UI inputs changed, run <code>pnpm canvas:a2ui:bundle</code> and commit any updated <a href="https://github.com/NJX-njx/opensoul/blob/main/src/canvas-host/a2ui/a2ui.bundle.js" target="_blank" rel="noreferrer"><code>src/canvas-host/a2ui/a2ui.bundle.js</code></a>.</li><li>[ ] <code>pnpm run build</code> (regenerates <code>dist/</code>).</li><li>[ ] Verify npm package <code>files</code> includes all required <code>dist/*</code> folders (notably <code>dist/node-host/**</code> and <code>dist/acp/**</code> for headless node + ACP CLI).</li><li>[ ] Confirm <code>dist/build-info.json</code> exists and includes the expected <code>commit</code> hash (CLI banner uses this for npm installs).</li><li>[ ] Optional: <code>npm pack --pack-destination /tmp</code> after the build; inspect the tarball contents and keep it handy for the GitHub release (do <strong>not</strong> commit it).</li></ul><ol start="3"><li><strong>Changelog &amp; docs</strong></li></ol><ul><li>[ ] Update <code>CHANGELOG.md</code> with user-facing highlights (create the file if missing); keep entries strictly descending by version.</li><li>[ ] Ensure README examples/flags match current CLI behavior (notably new commands or options).</li></ul><ol start="4"><li><strong>Validation</strong></li></ol><ul><li>[ ] <code>pnpm build</code></li><li>[ ] <code>pnpm check</code></li><li>[ ] <code>pnpm test</code> (or <code>pnpm test:coverage</code> if you need coverage output)</li><li>[ ] <code>pnpm release:check</code> (verifies npm pack contents)</li><li>[ ] <code>OPENSOUL_INSTALL_SMOKE_SKIP_NONROOT=1 pnpm test:install:smoke</code> (Docker install smoke test, fast path; required before release) <ul><li>If the immediate previous npm release is known broken, set <code>OPENSOUL_INSTALL_SMOKE_PREVIOUS=&lt;last-good-version&gt;</code> or <code>OPENSOUL_INSTALL_SMOKE_SKIP_PREVIOUS=1</code> for the preinstall step.</li></ul></li><li>[ ] (Optional) Full installer smoke (adds non-root + CLI coverage): <code>pnpm test:install:smoke</code></li><li>[ ] (Optional) Installer E2E (Docker, runs <code>curl -fsSL https://opensoul.ai/install.sh | bash</code>, onboards, then runs real tool calls): <ul><li><code>pnpm test:install:e2e:openai</code> (requires <code>OPENAI_API_KEY</code>)</li><li><code>pnpm test:install:e2e:anthropic</code> (requires <code>ANTHROPIC_API_KEY</code>)</li><li><code>pnpm test:install:e2e</code> (requires both keys; runs both providers)</li></ul></li><li>[ ] (Optional) Spot-check the web gateway if your changes affect send/receive paths.</li></ul><ol start="5"><li><strong>macOS app (Sparkle)</strong></li></ol><ul><li>[ ] Build + sign the macOS app, then zip it for distribution.</li><li>[ ] Generate the Sparkle appcast (HTML notes via <a href="https://github.com/NJX-njx/opensoul/blob/main/scripts/make_appcast.sh" target="_blank" rel="noreferrer"><code>scripts/make_appcast.sh</code></a>) and update <code>appcast.xml</code>.</li><li>[ ] Keep the app zip (and optional dSYM zip) ready to attach to the GitHub release.</li><li>[ ] Follow <a href="/docs/platforms/mac/release">macOS release</a> for the exact commands and required env vars. <ul><li><code>APP_BUILD</code> must be numeric + monotonic (no <code>-beta</code>) so Sparkle compares versions correctly.</li><li>If notarizing, use the <code>opensoul-notary</code> keychain profile created from App Store Connect API env vars (see <a href="/docs/platforms/mac/release">macOS release</a>).</li></ul></li></ul><ol start="6"><li><strong>Publish (npm)</strong></li></ol><ul><li>[ ] Confirm git status is clean; commit and push as needed.</li><li>[ ] <code>npm login</code> (verify 2FA) if needed.</li><li>[ ] <code>npm publish --access public</code> (use <code>--tag beta</code> for pre-releases).</li><li>[ ] Verify the registry: <code>npm view opensoul version</code>, <code>npm view opensoul dist-tags</code>, and <code>npx -y opensoul@X.Y.Z --version</code> (or <code>--help</code>).</li></ul><h3 id="troubleshooting-notes-from-2-0-0-beta2-release" tabindex="-1"><a class="header-anchor" href="#troubleshooting-notes-from-2-0-0-beta2-release">#</a> Troubleshooting (notes from 2.0.0-beta2 release)</h3><ul><li><strong>npm pack/publish hangs or produces huge tarball</strong>: the macOS app bundle in <code>dist/OpenSoul.app</code> (and release zips) get swept into the package. Fix by whitelisting publish contents via <code>package.json</code> <code>files</code> (include dist subdirs, docs, skills; exclude app bundles). Confirm with <code>npm pack --dry-run</code> that <code>dist/OpenSoul.app</code> is not listed.</li><li><strong>npm auth web loop for dist-tags</strong>: use legacy auth to get an OTP prompt: <ul><li><code>NPM_CONFIG_AUTH_TYPE=legacy npm dist-tag add opensoul@X.Y.Z latest</code></li></ul></li><li><strong><code>npx</code> verification fails with <code>ECOMPROMISED: Lock compromised</code></strong>: retry with a fresh cache: <ul><li><code>NPM_CONFIG_CACHE=/tmp/npm-cache-$(date +%s) npx -y opensoul@X.Y.Z --version</code></li></ul></li><li><strong>Tag needs repointing after a late fix</strong>: force-update and push the tag, then ensure the GitHub release assets still match: <ul><li><code>git tag -f vX.Y.Z &amp;&amp; git push -f origin vX.Y.Z</code></li></ul></li></ul><ol start="7"><li><strong>GitHub release + appcast</strong></li></ol><ul><li>[ ] Tag and push: <code>git tag vX.Y.Z &amp;&amp; git push origin vX.Y.Z</code> (or <code>git push --tags</code>).</li><li>[ ] Create/refresh the GitHub release for <code>vX.Y.Z</code> with <strong>title <code>opensoul X.Y.Z</code></strong> (not just the tag); body should include the <strong>full</strong> changelog section for that version (Highlights + Changes + Fixes), inline (no bare links), and <strong>must not repeat the title inside the body</strong>.</li><li>[ ] Attach artifacts: <code>npm pack</code> tarball (optional), <code>OpenSoul-X.Y.Z.zip</code>, and <code>OpenSoul-X.Y.Z.dSYM.zip</code> (if generated).</li><li>[ ] Commit the updated <code>appcast.xml</code> and push it (Sparkle feeds from main).</li><li>[ ] From a clean temp directory (no <code>package.json</code>), run <code>npx -y opensoul@X.Y.Z send --help</code> to confirm install/CLI entrypoints work.</li><li>[ ] Announce/share release notes.</li></ul><h2 id="plugin-publish-scope-npm" tabindex="-1"><a class="header-anchor" href="#plugin-publish-scope-npm">#</a> Plugin publish scope (npm)</h2><p>We only publish <strong>existing npm plugins</strong> under the <code>@opensoul/*</code> scope. Bundled plugins that are not on npm stay <strong>disk-tree only</strong> (still shipped in <code>extensions/**</code>).</p><p>Process to derive the list:</p><ol><li><code>npm search @opensoul --json</code> and capture the package names.</li><li>Compare with <code>extensions/*/package.json</code> names.</li><li>Publish only the <strong>intersection</strong> (already on npm).</li></ol><p>Current npm plugin list (update as needed):</p><ul><li>@opensoul/bluebubbles</li><li>@opensoul/diagnostics-otel</li><li>@opensoul/discord</li><li>@opensoul/feishu</li><li>@opensoul/lobster</li><li>@opensoul/matrix</li><li>@opensoul/msteams</li><li>@opensoul/nextcloud-talk</li><li>@opensoul/nostr</li><li>@opensoul/voice-call</li><li>@opensoul/zalo</li><li>@opensoul/zalouser</li></ul><p>Release notes must also call out <strong>new optional bundled plugins</strong> that are <strong>not on by default</strong> (example: <code>tlon</code>).</p>',28)])])}const m=o(s,[["render",n]]);export{h as __pageData,m as default};
